pub const KVM_CAP_VMI_INJECT: u32 = kvm_sys::KVM_CAP_VMI_INJECT;
pub const KVM_CAP_VMI_ALLOC_GFN: u32 = kvm_sys::KVM_CAP_VMI_ALLOC_GFN;
pub const KVM_CAP_NR_VCPUS: u32 = kvm_sys::KVM_CAP_NR_VCPUS;
